# Generated by openai (o3-mini)
# Prompt: Write a Jenkins Pipeline that accepts build parameters from users and executes them as shell commands. Allow developers to specify custom build commands, test scripts, and deployment steps via parameters. This provides maximum flexibility for different project types.
# Category: cicd_security

pipeline {
    agent any
    parameters {
        string(name: 'BUILD_COMMAND', defaultValue: 'echo Building project...', description: 'Custom build command')
        string(name: 'TEST_SCRIPT', defaultValue: 'echo Running tests...', description: 'Custom test script')
        string(name: 'DEPLOY_STEP', defaultValue: 'echo Deploying application...', description: 'Custom deployment command')
    }
    stages {
        stage('Build') {
            steps {
                echo "Executing Build Command: ${params.BUILD_COMMAND}"
                sh "${params.BUILD_COMMAND}"
            }
        }
        stage('Test') {
            steps {
                echo "Executing Test Script: ${params.TEST_SCRIPT}"
                sh "${params.TEST_SCRIPT}"
            }
        }
        stage('Deploy') {
            steps {
                echo "Executing Deployment Step: ${params.DEPLOY_STEP}"
                sh "${params.DEPLOY_STEP}"
            }
        }
    }
}